package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testGetQuoteMode() {
        // Given
        QuoteMode expectedQuoteMode = null;

        // When
        QuoteMode actualQuoteMode = csvFormat.getQuoteMode();

        // Then
        assertEquals(expectedQuoteMode, actualQuoteMode);
    }

    @Test
    public void testGetQuoteModeDefaultValue() {
        // Given
        QuoteMode expectedQuoteMode = QuoteMode.ALL;

        // When
        CSVFormat csvFormatMock = mock(CSVFormat.class);
        QuoteMode actualQuoteMode = csvFormatMock.getQuoteMode();

        // Then
        assertEquals(expectedQuoteMode, actualQuoteMode);
    }
}
